using Nethereum.ABI.FunctionEncoding.Attributes;
using Nethereum.Contracts;
using System.Numerics;

namespace Nethereum.Aspire.IntegrationTests.Infrastructure;

public static class ERC20TestHelper
{
    public const string BYTECODE = "";

    public const string ABI = @"[{""inputs"":[],""stateMutability"":""nonpayable"",""type"":""constructor""},{""inputs"":[{""internalType"":""address"",""name"":""to"",""type"":""address""},{""internalType"":""uint256"",""name"":""amount"",""type"":""uint256""}],""name"":""mint"",""outputs"":[],""stateMutability"":""nonpayable"",""type"":""function""},{""inputs"":[{""internalType"":""address"",""name"":""to"",""type"":""address""},{""internalType"":""uint256"",""name"":""value"",""type"":""uint256""}],""name"":""transfer"",""outputs"":[{""internalType"":""bool"",""name"":"""",""type"":""bool""}],""stateMutability"":""nonpayable"",""type"":""function""},{""anonymous"":false,""inputs"":[{""indexed"":true,""internalType"":""address"",""name"":""from"",""type"":""address""},{""indexed"":true,""internalType"":""address"",""name"":""to"",""type"":""address""},{""indexed"":false,""internalType"":""uint256"",""name"":""value"",""type"":""uint256""}],""name"":""Transfer"",""type"":""event""}]";

    public const string TransferEventSignature = "0xddf252ad1be2c89b69c2b068fc378daa952ba7f163c4a11628f55a4df523b3ef";

    public static async Task<string> DeployAsync(Nethereum.Web3.Web3 web3)
    {
        var gas = await web3.Eth.DeployContract.EstimateGasAsync(
            ABI, BYTECODE, web3.TransactionManager.Account.Address);
        var receipt = await web3.Eth.DeployContract.SendRequestAndWaitForReceiptAsync(
            ABI, BYTECODE, web3.TransactionManager.Account.Address, gas);
        return receipt.ContractAddress;
    }

    public static async Task MintAsync(Nethereum.Web3.Web3 web3, string contractAddress, string to, BigInteger amount)
    {
        var handler = web3.Eth.GetContractTransactionHandler<MintFunction>();
        await handler.SendRequestAndWaitForReceiptAsync(contractAddress,
            new MintFunction { To = to, Amount = amount });
    }

    public static async Task<string> TransferAsync(Nethereum.Web3.Web3 web3, string contractAddress, string to, BigInteger value)
    {
        var handler = web3.Eth.GetContractTransactionHandler<TransferFunction>();
        var receipt = await handler.SendRequestAndWaitForReceiptAsync(contractAddress,
            new TransferFunction { To = to, Value = value });
        return receipt.TransactionHash;
    }

    [Function("mint")]
    public class MintFunction : FunctionMessage
    {
        [Parameter("address", "to", 1)]
        public virtual string To { get; set; } = "";
        [Parameter("uint256", "amount", 2)]
        public virtual BigInteger Amount { get; set; }
    }

    [Function("transfer", "bool")]
    public class TransferFunction : FunctionMessage
    {
        [Parameter("address", "to", 1)]
        public virtual string To { get; set; } = "";
        [Parameter("uint256", "value", 2)]
        public virtual BigInteger Value { get; set; }
    }
}
